    "name": "EndpointDetailPageQuery",
    "operationKind": "query",
    "text": "query EndpointDetailPageQuery(\n  $endpointId: UUID!\n  $tokenListOffset: Int!\n  $tokenListLimit: Int!\n  $autoScalingRules_endpointId: String!\n  $autoScalingRules_filter: String\n  $autoScalingRules_offset: Int\n  $autoScalingRules_order: String\n  $autoScalingRules_before: String\n  $autoScalingRules_after: String\n  $autoScalingRules_first: Int\n  $autoScalingRules_last: Int\n  $skipScalingRules: Boolean!\n  $deploymentId: ID!\n  $routeFilter: RouteFilter\n  $healthyRouteFilter: RouteFilter\n  $routeOrderBy: [RouteOrderBy!]\n  $routeLimit: Int\n  $routeOffset: Int\n  $skipRouteNodes: Boolean!\n  $skipRoutings: Boolean!\n  $schedulingHistoryScope: DeploymentScope!\n  $schedulingHistoryFilter: DeploymentHistoryFilter\n  $skipSchedulingHistories: Boolean!\n) {\n  endpoint(endpoint_id: $endpointId) {\n    name\n    status\n    lifecycle_stage\n    endpoint_id\n    project\n    image_object {\n      namespace\n      humanized_name\n      tag\n      registry\n      architecture\n      is_local\n      digest\n      resource_limits {\n        key\n        min\n      }\n      labels {\n        key\n        value\n      }\n      size_bytes\n      supported_accelerators\n      ...ImageNodeSimpleTagFragment\n      id\n    }\n    replicas\n    url\n    open_to_public\n    errors {\n      session_id\n      ...InferenceSessionErrorModalFragment\n    }\n    retries\n    runtime_variant {\n      human_readable_name\n    }\n    model\n    model_mount_destination\n    model_definition_path\n    extra_mounts {\n      row_id\n      name\n      ...VFolderNodeIdenticonFragment\n      id\n    }\n    environ\n    resource_group\n    resource_slots\n    resource_opts\n    routings @skipOnClient(if: $skipRoutings) {\n      routing_id\n      session\n      traffic_ratio\n      endpoint\n      status\n      error_data\n      id\n    }\n    created_user_email\n    ...EndpointOwnerInfoFragment\n    ...EndpointStatusTagFragment\n    ...ServiceLauncherPageContentFragment\n    id\n  }\n  endpoint_token_list(offset: $tokenListOffset, limit: $tokenListLimit, endpoint_id: $endpointId) {\n    total_count\n    items {\n      id\n      token\n      endpoint_id\n      domain\n      project\n      session_owner\n      created_at\n      valid_until\n    }\n  }\n  endpoint_auto_scaling_rules: endpoint_auto_scaling_rule_nodes(endpoint: $autoScalingRules_endpointId, filter: $autoScalingRules_filter, order: $autoScalingRules_order, offset: $autoScalingRules_offset, before: $autoScalingRules_before, after: $autoScalingRules_after, first: $autoScalingRules_first, last: $autoScalingRules_last) @skipOnClient(if: $skipScalingRules) {\n    pageInfo {\n      hasNextPage\n      hasPreviousPage\n    }\n    edges {\n      node {\n        id\n        endpoint\n        metric_name\n        metric_source\n        threshold\n        comparator\n        step_size\n        cooldown_seconds\n        min_replicas\n        max_replicas\n        created_at\n        last_triggered_at\n        ...AutoScalingRuleEditorModalFragment\n      }\n    }\n  }\n  routes(deploymentId: $deploymentId, filter: $routeFilter, orderBy: $routeOrderBy, limit: $routeLimit, offset: $routeOffset) @skipOnClient(if: $skipRouteNodes) {\n    edges {\n      node {\n        ...BAIRouteNodesFragment\n        id\n      }\n    }\n    count\n  }\n  healthyRoutes: routes(deploymentId: $deploymentId, filter: $healthyRouteFilter) @skipOnClient(if: $skipRouteNodes) {\n    count\n  }\n  deploymentScopedSchedulingHistories(scope: $schedulingHistoryScope, filter: $schedulingHistoryFilter, limit: 1) @skipOnClient(if: $skipSchedulingHistories) {\n    count\n  }\n}\n\nfragment AutoScalingRuleEditorModalFragment on EndpointAutoScalingRuleNode {\n  id\n  endpoint\n  metric_name\n  metric_source\n  threshold\n  comparator\n  step_size\n  cooldown_seconds\n  min_replicas\n  max_replicas\n}\n\nfragment BAIRouteNodesFragment on Route {\n  id\n  status\n  healthStatus @since(version: \"26.4.0\")\n  trafficRatio\n  createdAt\n  errorData\n  session\n  trafficStatus\n}\n\nfragment EndpointOwnerInfoFragment on Endpoint {\n  id\n  created_user_email @since(version: \"23.09.8\")\n  session_owner_email @since(version: \"23.09.8\")\n}\n\nfragment EndpointStatusTagFragment on Endpoint {\n  id\n  status\n}\n\nfragment ImageNodeSimpleTagFragment on ImageNode {\n  base_image_name @since(version: \"24.12.0\")\n  version @since(version: \"24.12.0\")\n  architecture\n  name\n  tags @since(version: \"24.12.0\") {\n    key\n    value\n  }\n  labels {\n    key\n    value\n  }\n  registry\n  namespace @since(version: \"24.12.0\")\n  tag\n}\n\nfragment InferenceSessionErrorModalFragment on InferenceSessionError {\n  session_id\n  errors {\n    repr\n  }\n}\n\nfragment ServiceLauncherPageContentFragment on Endpoint {\n  endpoint_id\n  project\n  desired_session_count @deprecatedSince(version: \"24.12.0\")\n  replicas @since(version: \"24.12.0\")\n  resource_group\n  resource_slots\n  resource_opts\n  cluster_mode\n  cluster_size\n  open_to_public\n  model\n  model_mount_destination @since(version: \"24.03.4\")\n  model_definition_path @since(version: \"24.03.4\")\n  environ\n  runtime_variant @since(version: \"24.03.5\") {\n    name\n    human_readable_name\n  }\n  extra_mounts @since(version: \"24.03.4\") {\n    id\n    row_id\n    name\n  }\n  image_object @since(version: \"23.09.9\") {\n    name @deprecatedSince(version: \"24.12.0\")\n    namespace @since(version: \"24.12.0\")\n    humanized_name\n    tag\n    registry\n    architecture\n    is_local\n    digest\n    resource_limits {\n      key\n      min\n      max\n    }\n    labels {\n      key\n      value\n    }\n    size_bytes\n    supported_accelerators\n    id\n  }\n  name\n}\n\nfragment VFolderNodeIdenticonFragment on VirtualFolderNode {\n  id\n}\n"
